# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
from flask import Flask, request, jsonify

app = Flask(__name__)

def get_db_connection():
    return pymysql.connect(
        host='your_cloud_sql_host',
        user='your_username',
        password='your_password',
        db='your_database',
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor
    )

@app.route('/search', methods=['GET'])
def search_data():
    params = request.args
    query_parts = ['SELECT * FROM your_table']
    
    if 'column1' in params:
        query_parts.append(f"WHERE column1 LIKE '%{params['column1']}%'")
    
    if 'column2' in params:
        query_parts.append(f"AND column2 LIKE '%{params['column2']}%'")
    
    query = ' '.join(query_parts)
    
    conn = get_db_connection()
    with conn.cursor() as cursor:
        cursor.execute(query)
        result = cursor.fetchall()
    
    conn.close()
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)